defaultOptionValue:
{{ ((options, serverSideFiltering) => ( 
  (() => {
    const currentSelection = ModalInputRiskStatus.selectedOptionValue;

    if (currentSelection !== "At Risk") return null;

    // Hole alle At Risk Updates für diese Opportunity
    const data = Array.isArray(GetCurrentRiskStatus.data) ? 
                 GetCurrentRiskStatus.data : [];

    const oppHistory = data.filter(item => 
      item.opp_id === Renewal_List.selectedRow?.opportunity_id
    ).sort((a, b) => new Date(b.submit_timestamp) - new Date(a.submit_timestamp));

    // Finde letztes At Risk Update mit Risk Label
    const lastAtRisk = oppHistory.find(item => 
      item.risk_status === "At Risk" && item.risk_label
    );

    // Wenn es ein vorheriges At Risk gibt, übernimm die Category
    return lastAtRisk?.risk_label || null;
  })()
))(RiskCategory.options, RiskCategory.serverSideFiltering) }}

